(function(){
  'use strict';
  var th=document.getElementById('bfThickness'),w=document.getElementById('bfWidth'),l=document.getElementById('bfLength'),q=document.getElementById('bfQty'),btn=document.getElementById('calcBtn'),res=document.getElementById('result');
  function calc(){
    var t=parseFloat(th.value)||0,wi=parseFloat(w.value)||0,le=parseFloat(l.value)||0,qty=parseInt(q.value)||1;
    if(t<=0||wi<=0||le<=0)return;
    var cuIn=t*wi*le;
    var bf=cuIn/144;
    var totalBf=bf*qty;
    var cuFt=cuIn/1728;
    document.getElementById('rBFEach').textContent=bf.toFixed(2)+' BF';
    document.getElementById('rBFTotal').textContent=totalBf.toFixed(2)+' BF';
    document.getElementById('rCuIn').textContent=cuIn.toFixed(1)+' in³';
    document.getElementById('rCuFt').textContent=(cuFt*qty).toFixed(3)+' ft³';
    res.classList.add('visible');
  }
  btn.addEventListener('click',calc);
  [th,w,l,q].forEach(function(el){el.addEventListener('keydown',function(e){if(e.key==='Enter')calc();});});
})();

(function(){
  'use strict';
  var le=document.getElementById('glLength'),wi=document.getElementById('glWidth'),jo=document.getElementById('glJoints'),bo=document.getElementById('glBoth'),btn=document.getElementById('calcBtn'),res=document.getElementById('result');
  function calc(){
    var l=parseFloat(le.value)||0,w=parseFloat(wi.value)||0,j=parseInt(jo.value)||1;
    if(l<=0||w<=0)return;
    var singleArea=l*w;
    var sides=bo.value==='yes'?2:1;
    var totalArea=singleArea*sides*j;
    var mlNeeded=totalArea*0.05;
    var oz=mlNeeded/29.5735;
    var bottle=oz<=2?'4 oz bottle':oz<=4?'8 oz bottle':oz<=8?'16 oz bottle':'Quart or larger';
    document.getElementById('rArea').textContent=totalArea.toFixed(1)+' in²';
    document.getElementById('rGlue').textContent=mlNeeded.toFixed(1)+' mL';
    document.getElementById('rOz').textContent=oz.toFixed(2)+' fl oz';
    document.getElementById('rBottle').textContent=bottle;
    res.classList.add('visible');
  }
  btn.addEventListener('click',calc);
  [le,wi,jo,bo].forEach(function(el){el.addEventListener('keydown',function(e){if(e.key==='Enter')calc();});});
})();
